        Spreadsheet s = new Spreadsheet();
        s.setCellValue("A1", 5.0);
        s.setCellValue("A1", 99.0);
        s.undo();
        if (s.getCellNumericValue("A1") == 5.0) {
            s.redo();
            if (s.getCellNumericValue("A1") == 99.0) System.out.println("OK_UNDO_REDO");
        }
