}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        Spreadsheet s = new Spreadsheet();
        java.util.List<String> events = new java.util.ArrayList<>();
        s.addObserver((id, oldV, newV) -> events.add(id));
        s.setCellValue("A1", 1.0);
        s.setCellText("B1", "hi");
        if (events.size() == 2 && events.get(0).equals("A1") && events.get(1).equals("B1")) {
            System.out.println("OK_OBSERVER");
        }
    }
}
